const item = $input.first().json;

let emailText = '';

// METHOD 1: Gmail Get with Simplify ON gives text/html directly
if (item.text && item.text.length > 250) {
  emailText = item.text;
} else if (item.html && item.html.length > 250) {
  emailText = item.html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]*>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// METHOD 2: Raw payload — decode base64 from parts
if (!emailText || emailText.length < 250) {
  function decodeBody(payload) {
    if (!payload) return '';

    // Direct body data
    if (payload.body && payload.body.data) {
      try {
        const decoded = Buffer.from(
          payload.body.data.replace(/-/g, '+').replace(/_/g, '/'),
          'base64'
        ).toString('utf-8');
        if (payload.mimeType === 'text/plain') return decoded;
        if (payload.mimeType === 'text/html') {
          return decoded
            .replace(/<br\s*\/?>/gi, '\n')
            .replace(/<\/div>/gi, '\n')
            .replace(/<\/p>/gi, '\n')
            .replace(/<[^>]*>/g, '')
            .replace(/&nbsp;/g, ' ')
            .replace(/&amp;/g, '&')
            .replace(/\n{3,}/g, '\n\n')
            .trim();
        }
      } catch(e) {}
    }

    // Recurse into multipart parts
    if (payload.parts && payload.parts.length > 0) {
      let plainText = '';
      let htmlText = '';
      for (const part of payload.parts) {
        if (part.mimeType === 'text/plain' && part.body && part.body.data) {
          try {
            plainText = Buffer.from(
              part.body.data.replace(/-/g, '+').replace(/_/g, '/'),
              'base64'
            ).toString('utf-8');
          } catch(e) {}
        } else if (part.mimeType === 'text/html' && part.body && part.body.data) {
          try {
            const raw = Buffer.from(
              part.body.data.replace(/-/g, '+').replace(/_/g, '/'),
              'base64'
            ).toString('utf-8');
            htmlText = raw
              .replace(/<br\s*\/?>/gi, '\n')
              .replace(/<\/div>/gi, '\n')
              .replace(/<\/p>/gi, '\n')
              .replace(/<[^>]*>/g, '')
              .replace(/&nbsp;/g, ' ')
              .replace(/&amp;/g, '&')
              .replace(/\n{3,}/g, '\n\n')
              .trim();
          } catch(e) {}
        } else if (part.parts) {
          // Nested multipart
          const nested = decodeBody(part);
          if (nested.length > 0) return nested;
        }
      }
      // Prefer plain text, fallback to HTML
      if (plainText.length > 100) return plainText;
      if (htmlText.length > 100) return htmlText;
    }

    return '';
  }

  const decoded = decodeBody(item.payload);
  if (decoded.length > emailText.length) {
    emailText = decoded;
  }
}

// METHOD 3: Last resort — snippet
if (!emailText || emailText.length < 100) {
  emailText = item.snippet || '';
}

// Image attachments
const imageAttachments = [];
const keys = Object.keys(item);
for (const key of keys) {
  if (key.startsWith('attachment_')) {
    const att = item[key];
    if (att && att.mimeType && att.mimeType.startsWith('image/')) {
      imageAttachments.push({
        filename: att.fileName || 'attachment',
        mimeType: att.mimeType,
        data: att.data
      });
    }
  }
}

return [{
  json: {
    from: item.From || item.from || '',
    subject: item.Subject || item.subject || '',
    date: item.date || item.internalDate || '',
    text: emailText,
    textLength: emailText.length,
    hasImageAttachments: imageAttachments.length > 0,
    imageAttachments: imageAttachments,
    attachmentCount: imageAttachments.length
  }
}];

const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '';
const clean = content.replace(/```json|```/g, '').trim();
let parsed;
try { parsed = JSON.parse(clean); } catch (e) { throw new Error('JSON parse failed: ' + clean.substring(0, 200)); }

return [{ json: {
  processed_at: new Date().toISOString(),
  customer_name: parsed.customer?.name || '',
  customer_company: parsed.customer?.company || '',
  customer_email: parsed.customer?.email || '',
  customer_phone: parsed.customer?.phone || '',
  customer_role: parsed.customer?.role || '',
  industry: parsed.enquiry?.industry || '',
  num_items: parsed.enquiry?.items?.length || 0,
  items_detail: parsed.enquiry?.items?.map(i => `${i.quantity}x ${i.product_type} (${i.dimensions?.length_mm || '?'}x${i.dimensions?.width_mm || '?'}x${i.dimensions?.height_mm || '?'}mm)`).join(' | ') || '',
  services: parsed.enquiry?.services_needed?.join(', ') || '',
  deadline: parsed.enquiry?.deadline || '',
  urgency: parsed.enquiry?.urgency || 'low',
  attachments: parsed.enquiry?.attachments_mentioned || false,
  attachment_analysis: parsed.attachment_analysis || '',
  confidence: parsed.confidence_score || 0,
  summary: parsed.summary || '',
  missing_info: parsed.missing_info?.join(', ') || '',
  followup: parsed.suggested_followup || '',
  full_json: JSON.stringify(parsed)
} }];

